#include <stdio.h>
#include <stdlib.h>

// Structure of Node
struct Node {
    int data;
    struct Node* next;
};

// Function to create a new node
struct Node* createNode(int x) {
    struct Node* newNode = (struct Node*)malloc(sizeof(struct Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->data = x;
    newNode->next = NULL;
    return newNode;
}

// Function to sort the linked list of 0s, 1s, and 2s (in-place)
struct Node* sortList(struct Node* head) {
    if (head == NULL || head->next == NULL)
        return head;

    struct Node* zeroHead = createNode(-1);
    struct Node* oneHead  = createNode(-1);
    struct Node* twoHead  = createNode(-1);

    struct Node* zero = zeroHead;
    struct Node* one  = oneHead;
    struct Node* two  = twoHead;

    struct Node* curr = head;
    while (curr != NULL) {
        if (curr->data == 0) {
            zero->next = curr;
            zero = zero->next;
        } else if (curr->data == 1) {
            one->next = curr;
            one = one->next;
        } else {
            two->next = curr;
            two = two->next;
        }
        curr = curr->next;
    }

    // Connect 0s → 1s → 2s
    zero->next = (oneHead->next != NULL) ? oneHead->next : twoHead->next;
    one->next = twoHead->next;
    two->next = NULL;

    struct Node* newHead = zeroHead->next;

    // Delete dummy nodes to avoid memory leak
    free(zeroHead);
    free(oneHead);
    free(twoHead);

    return newHead;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        struct Node* head = NULL;
        struct Node* tail = NULL;
        for (int i = 0; i < N; i++) {
            int x;
            scanf("%d", &x);
            struct Node* newNode = createNode(x);
            if (head == NULL) {
                head = newNode;
                tail = newNode;
            } else {
                tail->next = newNode;
                tail = newNode;
            }
        }
        head = sortList(head);
        while (head != NULL) {
            printf("%d ", head->data);
            head = head->next;
        }
        printf("\n");
    }
    return 0;
}

